### Recipe 03 — Fallback chain with self-logged routing visibility

**Goal:** Configure a primary model with a fallback chain, capture whether the fallback fired (given that the gateway does not surface `modelAttempts` in API-key mode), and emit a structured log that downstream observability can use.

#### Implementation

The core logic uses the `@ai-sdk/gateway` to define a primary model and a list of fallback models. Because the gateway does not return metadata about which model actually served the request when using API-key mode, we emit a structured log at the start and end of the call to provide visibility.

```ts
// src/primitive.ts
import { generateText } from 'ai';
import { createGateway } from '@ai-sdk/gateway';
import { loadConfig } from './config.js';

export interface GenerateOptions {
  prompt: string;
  model: string;
  fallbackModels?: string[];
  maxOutputTokens?: number;
}

export interface GenerateResult {
  text: string;
  usage: { inputTokens: number; outputTokens: number; totalTokens: number };
  finishReason: string;
  latency_ms: number;
  requestId: string;
  gatewayMetaDefined: boolean; // typically false in API-key mode
}

export async function generate(opts: GenerateOptions): Promise<GenerateResult> {
  const cfg = loadConfig();
  const gateway = createGateway({ apiKey: cfg.apiKey });
  const requestId = `gen-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`;

  // Log intent: what we are trying to do
  console.log(JSON.stringify({
    op: 'generate-start',
    requestId,
    model: opts.model,
    fallbackModels: opts.fallbackModels ?? [],
    apiKeyMasked: cfg.apiKeyMasked,
  }));

  const t0 = Date.now();
  let result;
  try {
    result = await generateText({
      model: gateway(opts.model),
      prompt: opts.prompt,
      maxOutputTokens: opts.maxOutputTokens ?? 50,
      providerOptions: {
        gateway: {
          ...(opts.fallbackModels?.length ? { models: opts.fallbackModels } : {}),
          tags: ['fallback-recipe'],
        },
      },
    });
  } catch (err) {
    const errorMessage = (err instanceof Error ? err.message : String(err)).substring(0, 300);
    console.log(JSON.stringify({ op: 'generate-error', requestId, errorMessage }));
    throw err;
  }
  const latency_ms = Date.now() - t0;

  // In API-key mode, gateway metadata is usually absent. 
  // In OIDC mode, it may be present.
  const gatewayMetaDefined = result.experimental_providerMetadata?.gateway != null;
  const usage = result.usage as { inputTokens: number; outputTokens: number; totalTokens: number };

  // Log outcome: latency and usage
  console.log(JSON.stringify({
    op: 'generate-success',
    requestId,
    latency_ms,
    inputTokens: usage.inputTokens,
    outputTokens: usage.outputTokens,
    totalTokens: usage.totalTokens,
    finishReason: result.finishReason,
    textLength: result.text.length,
    gatewayMetaDefined,
    note: gatewayMetaDefined ? 'metadata present (OIDC?)' : 'metadata absent (API-key mode)',
  }));

  return {
    text: result.text,
    usage,
    finishReason: result.finishReason,
    latency_ms,
    requestId,
    gatewayMetaDefined,
  };
}
```

#### Driver

```ts
// src/run-recipe.ts
import { generate } from './primitive.js';

async function main() {
  // Happy path — primary works
  const a = await generate({
    prompt: "Reply with 'pong'",
    model: 'openai/gpt-5.4-nano',
    fallbackModels: ['anthropic/claude-haiku-4-5'],
    maxOutputTokens: 5,
  });
  console.log('happy:', a.text);

  // Fallback path — primary is unambiguously bad
  const b = await generate({
    prompt: "Reply with 'pong'",
    model: 'nonexistent/model-that-does-not-exist-' + Date.now(),
    fallbackModels: ['openai/gpt-5.4-nano'],
    maxOutputTokens: 5,
  });
  console.log('fallback:', b.text);
}

main().catch((e) => { console.error(e); process.exit(1); });
```

#### Expected Output

```json
{"op":"generate-start","requestId":"gen-...","model":"openai/gpt-5.4-nano","fallbackModels":["anthropic/claude-haiku-4-5"],"apiKeyMasked":"vck_1l0I..."}
{"op":"generate-success","requestId":"gen-...","latency_ms":827,"inputTokens":14,"outputTokens":5,"totalTokens":19,"finishReason":"stop","textLength":4,"gatewayMetaDefined":false,"note":"metadata absent (API-key mode)"}
happy: pong

{"op":"generate-start","requestId":"gen-...","model":"nonexistent/model-that-does-not-exist-...","fallbackModels":["openai/gpt-5.4-nano"],"apiKeyMasked":"vck_1l0I..."}
{"op":"generate-success","requestId":"gen-...","latency_ms":711,"inputTokens":14,"outputTokens":5,"totalTokens":19,"finishReason":"stop","textLength":4,"gatewayMetaDefined":false,"note":"metadata absent (API-key mode)"}
fallback: pong
```

Both calls return `"pong"`. The second proves the fallback fired. Latency is similar (711ms vs 827ms) — do not use latency to detect fallbacks.

The proven pattern for **P-001: `Annotation.Root` with custom reducer (concat / accumulator)** in LangGraph is to declare state channels with an explicit `reducer` function and a `default` value. This allows multiple nodes to contribute to a single field (like logs or findings) without overwriting each other.

### Implementation Pattern

```typescript
import { Annotation } from "@langchain/langgraph";

const GraphState = Annotation.Root({
  // Accumulator pattern: sums values
  counter: Annotation<number>({
    reducer: (l, r) => l + r,
    default: () => 0,
  }),
  // Concat pattern: appends new items to a list
  log: Annotation<string[]>({
    reducer: (l, r) => l.concat(r),
    default: () => [],
  }),
  // LastValue pattern: bare Annotation (no reducer)
  // Concurrent writes to this field will throw InvalidUpdateError
  status: Annotation<string>,
});
```

### Key Rules & Gotchas

1.  **The "New Only" Rule (Critical)**: When a node returns a value for a reducer-enabled field, it must return **only the new entries** for that turn.
    *   **Correct**: `return { findings: ["new finding"] };` (The reducer appends this to the existing array).
    *   **Incorrect**: `return { findings: [...state.findings, "new finding"] };` (This double-counts the existing findings).
2.  **Bare Annotation = LastValue**: Using `Annotation<T>` without a reducer function defaults to `LastValue` semantics. If two parallel nodes attempt to write to a bare annotation simultaneously, LangGraph will throw an `InvalidUpdateError`.
3.  **Default Values**: Always provide a `default` function (e.g., `default: () => []`) to ensure the reducer has a valid initial state to work with.

### When to use it
*   **Logs/Audit Trails**: Collecting messages or events from multiple nodes.
*   **Findings/Results**: Aggregating research findings from parallel worker nodes.
*   **Counters**: Tracking token usage, error counts, or iteration steps across the graph.

The proven pattern for proxying Workers AI inference calls through AI Gateway is to route the request through the gateway URL (Option A) or use the `gateway` option in the AI binding (Option B).

### Option A: Direct fetch to the gateway URL
This is the most flexible method, allowing you to explicitly set cache TTLs and inspect observability headers.

```typescript
// wrangler.toml:
// [vars]
// ACCOUNT_ID = "your_account_id"
// GATEWAY_ID = "your_gateway_id"

export default {
  async fetch(req: Request, env: { CF_AI_TOKEN: string, ACCOUNT_ID: string, GATEWAY_ID: string }): Promise<Response> {
    const prompt = new URL(req.url).searchParams.get('prompt') ?? 'hi';
    const MODEL = '@cf/meta/llama-3.1-8b-instruct';

    // Provider slug is `workers-ai` (hyphenated) — NOT `workersai`
    const gwUrl = `https://gateway.ai.cloudflare.com/v1/${env.ACCOUNT_ID}/${env.GATEWAY_ID}/workers-ai/${MODEL}`;

    const r = await fetch(gwUrl, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${env.CF_AI_TOKEN}`,  // ai:write token
        'Content-Type': 'application/json',
        'cf-aig-cache-ttl': '3600',  // 1 hour cache
      },
      body: JSON.stringify({ prompt, max_tokens: 100 }),
    });

    // Capture observability headers
    const cacheStatus = r.headers.get('cf-aig-cache-status');  // HIT or MISS
    const step = r.headers.get('cf-aig-step');                 // 0-indexed provider in chain

    console.log(JSON.stringify({
      event: 'gateway_call',
      cache_status: cacheStatus,
      step,
      status: r.status,
    }));

    const json = await r.json() as { result: { response: string }, success: boolean };
    return new Response(json.result.response);
  }
};
```

### Option B: AI binding with `gateway` option
This is the cleanest syntax if you are already using the `[ai]` binding in your Worker.

```typescript
// wrangler.toml:
// [ai]
// binding = "AI"
// remote = true  // required for wrangler dev

const result = await env.AI.run('@cf/meta/llama-3.1-8b-instruct', {
  prompt: 'hi',
  max_tokens: 100,
}, {
  gateway: {
    id: 'your_gateway_id',
    cacheTtl: 3600,
  },
});
```

### Key Implementation Gotchas
- **Provider Slug:** Use `workers-ai` (hyphenated) in the URL, not `workersai`.
- **Auth Token:** Use the same `ai:write` token (or Wrangler OAuth token) as you would for direct Workers AI calls.
- **Request/Response Shape:** The request body and response shape are identical to direct Workers AI calls (e.g., `{ prompt, max_tokens }` and `{ result: { response: string }, success: true }`), **not** OpenAI's format.
- **Observability:** Use the `cf-aig-cache-status` and `cf-aig-step` headers to debug cache hits and gateway routing.

The gotcha is that LangChain's typed error classes (like `AuthenticationError`, `NotFoundError`, `RateLimitError`, etc.) do not override the `name` property in their constructors. Consequently, **`err.name` will always return the literal string `"Error"`**, even if the error is an instance of a specific subclass.

### Why it happens
LangChain's error classes extend the base `Error` class but omit the `this.name = "ClassName"` assignment in the subclass constructor. This breaks the standard JavaScript convention where `err.name` matches the class name.

### How to avoid it
Do not use `err.name` for error discrimination. Instead, use one of the following three patterns:

#### 1. Use `err.constructor.name` (Recommended)
This is the most direct way to access the actual class name.

```typescript
try {
  await model.invoke(messages);
} catch (err: any) {
  switch (err.constructor.name) {
    case "AuthenticationError":  return { retry: false, surfaceAs: "BAD_KEY" };
    case "NotFoundError":         return { retry: false, surfaceAs: "BAD_MODEL" };
    case "ContextOverflowError":  return { retry: true,  surfaceAs: "TRIM_INPUT" };
    case "RateLimitError":        return { retry: false, surfaceAs: "RATE_LIMITED_EXCEEDED" };
    case "ServiceUnavailableError":return { retry: true, surfaceAs: "PROVIDER_5XX" };
    default:                      return { retry: false, surfaceAs: "UNKNOWN" };
  }
}
```

#### 2. Use `instanceof`
If you have access to the LangChain error classes in your scope, `instanceof` is the most type-safe approach.

```typescript
import { AuthenticationError, NotFoundError } from "@langchain/core/errors";

try {
  await model.invoke(messages);
} catch (err: any) {
  if (err instanceof AuthenticationError) {
    // handle auth error
  } else if (err instanceof NotFoundError) {
    // handle not found
  }
}
```

#### 3. Inspect the message string (Fallback)
If you are in a bundled environment where class identities might be lost or you want a more robust check against the underlying provider's error message:

```typescript
try {
  await model.invoke(messages);
} catch (err: any) {
  const msg = err.message || "";
  if (msg.includes("authentication_error")) { /* ... */ }
  if (msg.includes("not_found_error"))       { /* ... */ }
  if (msg.includes("too long"))              { /* ContextOverflowError */ }
}
```

### Verification
You can verify this behavior yourself by intentionally passing an invalid API key:
```typescript
try {
  await new ChatAnthropic({ apiKey: "sk-ant-INVALID" }).invoke("hi");
} catch (err: any) {
  console.log(err.name);              // Output: "Error"
  console.log(err.constructor.name);  // Output: "AuthenticationError"
}
```

# Cloudflare AI Search: Practical Quickstart

Cloudflare AI Search is a managed RAG (Retrieval-Augmented Generation) service that combines a vector database (Vectorize), an embedding model, and a language model (Workers AI) into a single API.

## 1. Core Concepts
*   **Data Sources:** You ingest data from **Websites** (crawled by Cloudflare) or **R2 Buckets** (your own files).
*   **Embedding Model:** Chosen at instance creation. **Cannot be changed later** without re-ingesting all data.
*   **Retrieval + Generation:** The `chatCompletions` API retrieves relevant chunks and generates a response in one call.

---

## 2. Quickstart: Setup & Ingestion

### Step A: Create an AI Search Instance
1.  Go to the **Cloudflare Dashboard** > **AI Search**.
2.  Click **Create Instance**.
3.  **Select Data Source:**
    *   **Website:** Enter a domain you own (must be on the same Cloudflare account).
    *   **R2 Bucket:** Select an existing R2 bucket.
4.  **Select Embedding Model:** Choose a model (e.g., `@cf/baai/bge-m3` for multilingual or `@cf/baai/bge-large-en-v1.5` for English).
5.  **Wait for Ingestion:** Cloudflare will crawl the site or sync the R2 bucket.

### Step B: Verify Ingestion
Check the instance dashboard to see the number of pages/files indexed and the status of the last sync.

---

## 3. Implementation: Chat with your Data

The most practical way to use AI Search is via a **Cloudflare Worker** using the built-in binding.

### Worker Code (`src/index.ts`)
```typescript
export interface Env {
  // The binding name you set in wrangler.toml
  MY_SEARCH: any; 
}

export default {
  async fetch(request: Request, env: Env): Promise<Response> {
    const { query } = await request.json() as { query: string };

    try {
      // chatCompletions performs retrieval + generation in one step
      const response = await env.MY_SEARCH.chatCompletions({
        messages: [
          { role: "system", content: "You are a helpful assistant that answers questions based on the provided context." },
          { role: "user", content: query }
        ],
        model: "@cf/meta/llama-3.3-70b-instruct-fp8-fast", // Generation model
        ai_search_options: {
          retrieval: { max_num_results: 5 }, // How many chunks to retrieve
          query_rewrite: { enabled: true }   // Automatically improves the search query
        }
      });

      return new Response(JSON.stringify(response), {
        headers: { "Content-Type": "application/json" }
      });
    } catch (err: any) {
      return new Response(JSON.stringify({ error: err.message }), { status: 500 });
    }
  }
};
```

### Wrangler Configuration (`wrangler.toml`)
```toml
name = "ai-search-worker"
main = "src/index.ts"
compatibility_date = "2025-01-01"

[[ai_search_bindings]]
name = "MY_SEARCH"
instance_id = "your-instance-id-from-dashboard"
```

---

## 4. Advanced Patterns

### Streaming Responses
For a better UX, stream the response to the client:
```typescript
const response = await env.MY_SEARCH.chatCompletions({
  messages: [{ role: "user", content: query }],
  model: "@cf/meta/llama-3.3-70b-instruct-fp8-fast",
  stream: true // Enable streaming
});

// response is a ReadableStream of SSE events
return new Response(response, {
  headers: { "Content-Type": "text/event-stream" }
});
```

### Using External Models (OpenAI/Anthropic)
If you prefer OpenAI's embeddings or GPT-4o for generation:
1.  Set up **Cloudflare AI Gateway**.
2.  Add your provider API keys to the Gateway.
3.  In AI Search, select the external model (e.g., `openai/text-embedding-3-small`) during instance creation.

## 5. Gotchas & Limits
*   **Embedding Lock-in:** You cannot change the embedding model after creation. To switch, you must create a new instance and re-ingest.
*   **Website Crawling:** Only domains on the **same Cloudflare account** can be crawled.
*   **R2 Sync:** Minimum sync cooldown is 3 minutes.
*   **Bot Detection:** If you use Cloudflare WAF/Bot Management, you must create an exception for the `Cloudflare-AI-Search` user agent.

The error `"Model 'X' not found"` typically occurs when an invalid, misspelled, or deprecated model ID is passed to an AI SDK or gateway.

### 1. Diagnose the Root Cause
*   **Check for Typos:** Verify the model string exactly matches the provider's expected ID (e.g., `gpt-4o` vs `gpt4o`).
*   **Check for Deprecation:** The model might have been removed or renamed by the provider.
*   **Check Tier/Access:** Some models (like `claude-3-5-sonnet-latest`) are tier-dependent; if your API key doesn't have access, the gateway may return a "not found" error.
*   **Check the Provider Prefix:** If using a gateway (like Vercel AI Gateway), ensure the provider prefix is correct (e.g., `openai/gpt-4o` vs just `gpt-4o`).

### 2. Fix the Request
*   **Use Explicit IDs:** Instead of using aliases like `*-latest` (which can be inconsistent across environments), use the specific versioned ID (e.g., `claude-3-5-haiku-20241022`).
*   **Verify via API:** Query the provider's `/v1/models` endpoint (if available) to see the current list of valid model IDs.

### 3. Add a Fallback (Safety Net)
To prevent a single typo or model outage from breaking your application, implement a fallback mechanism. If you are using the Vercel AI Gateway, you can configure a fallback model in your request:

```ts
await generateText({
  model: 'openai/gpt-5.4-nano', // Primary model
  prompt: '...',
  providerOptions: {
    gateway: {
      models: ['anthropic/claude-haiku-4-5'], // Fallback if primary fails
    },
  },
});
```

### 4. Error Handling Pattern
In your code, you can catch this specific error to provide a graceful fallback or a user-friendly message:

```ts
try {
  const result = await generateText({ ... });
} catch (err) {
  if (err instanceof Error && err.message.includes('not found')) {
    // Handle model_not_found (e.g., log to Sentry, switch to a default model)
    console.error("Model not found. Falling back to default model.");
  }
}
```

The "gotcha" is that pi's permissive parsing is a double-edged sword: while it allows you to add custom annotations without breaking anything, it also means **pi cannot distinguish between a custom annotation and a typo on an official key.**

### The Risk
If you misspell an official key (e.g., writing `base_url` instead of `baseUrl`), pi will silently ignore your typo and treat the field as a custom annotation. You won't get a parse error, but your configuration won't behave as expected (e.g., the provider will try to hit the default URL instead of your custom one).

### How to avoid it
1.  **Prefix custom keys**: Use a `_` or `x-` prefix for your own annotations (e.g., `_tier`, `_max_context`). This makes it visually obvious that the key is not part of the official pi schema and prevents accidental collisions with future official fields.
2.  **Treat annotations as additive only**: Do not rely on pi to read your annotations. They are purely for your own tooling or extensions.
3.  **Verify official keys**: Since there is no "unknown field" error, you must manually verify that your official keys (like `baseUrl`, `api`, `apiKey`, `id`, `name`) are spelled exactly as required by the pi schema.

**Example of safe annotation usage:**
```jsonc
{
  "providers": {
    "deepseek": {
      "baseUrl": "https://api.deepseek.com/v1",
      "api": "openai-completions",
      "apiKey": "DEEPSEEK_API_KEY",
      "_tier": "hosted-cheap",          // Safe: prefixed and visually distinct
      "models": [
        {
          "id": "deepseek-chat",
          "name": "DeepSeek Chat",
          "_role": "default-hosted"     // Safe: prefixed
        }
      ]
    }
  }
}
```

The gotcha is that `AIMessage.content` is **polymorphic**: it can be a plain `string` (for simple text responses) OR an `array` of content blocks (for tool calls, thinking blocks, or multi-modal content).

### The Symptom
If you assume `.content` is always a string and call string methods on it, your code will crash when the model uses a tool:

```typescript
const res = await model.invoke("Say READY");
// ❌ CRASHES when res.content is [{ type: "tool_use", ... }]
console.log(res.content.toUpperCase()); 
// TypeError: res.content.toUpperCase is not a function
```

### How to avoid it

#### 1. Use a robust extraction helper (Recommended for manual handling)
If you need to inspect the message yourself, use a helper that handles both shapes:

```typescript
function extractText(content: unknown): string {
  if (typeof content === "string") return content;
  if (Array.isArray(content)) {
    return content
      .filter((block: any) => block.type === "text")
      .map((block: any) => block.text)
      .join("");
  }
  return String(content ?? "");
}

const res = await model.invoke("Say READY");
console.log(extractText(res.content).toUpperCase()); // Safe
```

#### 2. Use `StringOutputParser` (Recommended for LCEL chains)
If you only care about the text output, pipe your chain into a `StringOutputParser`. It handles the extraction/joining logic for you, ensuring the output is always a plain string.

```typescript
import { StringOutputParser } from "@langchain/core/output_parsers";

const chain = prompt.pipe(model).pipe(new StringOutputParser());
const text = await chain.invoke({...}); 
console.log(text.toUpperCase()); // Always safe
```

### Why it happens
The Anthropic Messages API natively returns `content` as an array of blocks (e.g., `[{ type: "text", text: "..." }]`). `@langchain/anthropic` normalizes this:
- For simple text-only responses, it collapses the array into a plain string.
- For responses involving tool calls (or other multi-modal blocks), it preserves the array shape.

To create a test user in Supabase, you must use the `service_role` key to bypass email confirmation. Without setting `email_confirm: true`, the user will be created in an unconfirmed state, and `signInWithPassword` will fail.

Below is a production-ready TypeScript recipe for creating a confirmed test user and returning a ready-to-use authenticated client.

### TypeScript Recipe: Create + Sign-In Test User

```typescript
import { createClient, type SupabaseClient } from '@supabase/supabase-js'

// These must be set in your environment
const SUPABASE_URL = process.env.SUPABASE_URL!
const ANON = process.env.SUPABASE_ANON_KEY!
const SERVICE_ROLE = process.env.SUPABASE_SERVICE_ROLE_KEY!

// A unique prefix for test users to avoid collisions and allow easy cleanup
const TEST_PREFIX = `au_test_${Date.now()}_`

export interface TestUser {
  id: string
  email: string
  password: string
  client: SupabaseClient    // An authenticated client for the test user
  jwt: string               // The access token
}

/**
 * Creates a confirmed test user via the service_role, signs them in,
 * and returns a ready-to-use authenticated client.
 */
export async function createTestUser(label: string = 'generic'): Promise<TestUser> {
  // Use a reserved RFC 2606 domain for test emails
  const email = `${TEST_PREFIX}${label}@test.example`
  const password = `test-pw-${crypto.randomUUID().slice(0, 8)}`

  // 1. Create the user via admin API
  // email_confirm: true is CRITICAL to bypass the confirmation email flow
  const adminClient = createClient(SUPABASE_URL, SERVICE_ROLE, {
    auth: { autoRefreshToken: false, persistSession: false }
  })

  const { data: created, error: createErr } = await adminClient.auth.admin.createUser({
    email,
    password,
    email_confirm: true,
    user_metadata: { source: 'test-suite' },
  })
  if (createErr) throw createErr
  const userId = created.user!.id

  // 2. Sign in via a fresh anon client to mint a JWT
  const signinClient = createClient(SUPABASE_URL, ANON, {
    auth: { autoRefreshToken: false, persistSession: false }
  })
  const { data: session, error: signinErr } = await signinClient.auth.signInWithPassword({
    email,
    password,
  })
  if (signinErr) throw signinErr
  const jwt = session.session!.access_token

  // 3. Build a user-context client carrying the JWT as Bearer
  const client = createClient(SUPABASE_URL, ANON, {
    global: { headers: { Authorization: `Bearer ${jwt}` } },
    auth: { autoRefreshToken: false, persistSession: false },
  })

  return { id: userId, email, password, client, jwt }
}

/**
 * Deletes the test user via the service_role.
 */
export async function deleteTestUser(userId: string) {
  const adminClient = createClient(SUPABASE_URL, SERVICE_ROLE, {
    auth: { autoRefreshToken: false, persistSession: false }
  })
  await adminClient.auth.admin.deleteUser(userId)
}
```

### Key Implementation Details

1.  **`email_confirm: true`**: This is the most important flag. Without it, the user is created but cannot sign in until they click a link in an email you cannot access during automated tests.
2.  **`service_role` vs `anon`**:
    *   The **`service_role`** key is used to create the user (bypassing all security).
    *   The **`anon`** key is used to sign in the user to get a real JWT.
3.  **RFC 2606 Domains**: Using `@test.example` or `@agent-university.test` ensures you never accidentally send real emails to real people during testing.
4.  **User-Context Client**: The returned `client` is pre-configured with the user's JWT in the `Authorization` header. This allows you to immediately run queries like `client.from('profiles').select('*')` and have RLS applied correctly.

The proven pattern for **P-001: `try/finally + flush()` cleanup pattern** in LangSmith is to wrap your main execution block in a `try/finally` and call `flush()` on the relevant client(s) within the `finally` block. This ensures that traces are uploaded even if the work throws an error, and prevents data loss when the process exits.

### Implementation Pattern

```typescript
import { Client } from "langsmith";
import { traceable } from "langsmith/traceable";
import { RunTree } from "langsmith/run_trees";

async function main() {
  // 1. Create your client (if you'll use it directly)
  const client = new Client();

  // 2. Define your traced work
  const tracedWork = traceable(async () => {
    // ... your real work
  }, { name: "main" });

  try {
    // 3. Execute the work
    await tracedWork();
  } finally {
    // 4. CRITICAL: Flush the SHARED client used by traceable/wrapAnthropic/LangChain
    // This is the most common source of silent data loss.
    await RunTree.getSharedClient().flush();

    // 5. If you also used `client` directly (e.g., client.createRun()), flush it too.
    // These are separate queues; flushing one does not flush the other.
    await client.flush();
  }
}

await main();
```

### Key Details

| If your code uses... | Flush this |
| :--- | :--- |
| `traceable()` | `RunTree.getSharedClient().flush()` |
| `wrapAnthropic()` | `RunTree.getSharedClient().flush()` |
| LangChain auto-tracing | `RunTree.getSharedClient().flush()` |
| `client.createRun()` directly | `client.flush()` on THAT specific client |
| Both | Flush both |

### Why this pattern is required

1.  **Prevents data loss on `process.exit()`**: Without `await flush()`, the SDK's background queue is killed before its 250ms timer fires. Traces are dropped 100% of the time in this race.
2.  **Ensures traces on error paths**: The `finally` block ensures that even if your work throws an exception, the trace (which will contain the error details) is still uploaded for debugging.
3.  **Correct client targeting**: A common mistake is flushing a new `Client()` instance instead of the shared client used by `traceable()`. This results in no traces being uploaded because the queue you flushed was empty.

### Related Gotchas
- **G-001**: `process.exit()` drops traces without flush.
- **G-002**: Flushing a new client instead of `RunTree.getSharedClient()`.

To sign in a user anonymously and then identify them (upgrade them to a named account) in Supabase, you follow a two-step flow. The key advantage of this pattern is that the user's unique ID (`sub`) remains the same when they sign up, meaning all data they created while anonymous automatically belongs to their new named account.

### 1. Prerequisites
You must enable anonymous sign-ins in your Supabase project.
- **Dashboard:** Authentication → Settings → Anonymous Sign-Ins → **ON**
- **Local CLI:** In `supabase/config.toml`, set `enable_anonymous_sign_ins = true`.

### 2. Implementation

#### Step A: Sign in anonymously
This creates a unique user with a generated UUID and a JWT where `is_anonymous: true`.

```typescript
import { createClient } from '@supabase/supabase-js'

const supabase = createClient(
  process.env.SUPABASE_URL!,
  process.env.SUPABASE_ANON_KEY!
)

// Create an anonymous session
const { data, error } = await supabase.auth.signInAnonymously()

if (error) {
  console.error('Error signing in anonymously:', error.message)
  return
}

const { session, user } = data
console.log('Anonymous User ID:', user.id) // A generated UUID
console.log('Is Anonymous:', user.is_anonymous) // true

// The user can now perform actions (e.g., create a todo)
// RLS should use `auth.uid() = user_id`
await supabase.from('todos').insert({
  user_id: user.id,
  task: 'My guest task'
})
```

#### Step B: Identify the user (Upgrade to named account)
When the user decides to sign up, call `updateUser`. This attaches an email/password to the **existing** UUID.

```typescript
// The user provides their email and password
const { data: upgradeData, error: upgradeError } = await supabase.auth.updateUser({
  email: 'user@example.com',
  password: 'secure-password-123'
})

if (upgradeError) {
  console.error('Upgrade failed:', upgradeError.message)
  return
}

// SUCCESS:
// 1. The user's ID (user.id) is UNCHANGED.
// 2. All rows created while anonymous (keyed on user.id) now belong to this named account.
// 3. user.is_anonymous is now false.
console.log('User upgraded successfully. New email:', upgradeData.user.email)
```

### 3. Critical Gotcha: RLS and Roles
A common mistake is assuming anonymous users have the `anon` role. They do **not**.

| User Type | JWT `role` | JWT `is_anonymous` |
| :--- | :--- | :--- |
| **Unauthenticated** | `anon` | (not present) |
| **Anonymous** | `authenticated` | `true` |
| **Named User** | `authenticated` | `false` |

**Correct RLS for anonymous users:**
```sql
-- This works for both anonymous and named users
CREATE POLICY "Users can manage their own todos"
ON todos FOR ALL
TO authenticated
USING (auth.uid() = user_id);

-- If you need to specifically target ONLY anonymous users:
CREATE POLICY "Anonymous users can only read"
ON todos FOR SELECT
TO authenticated
USING ((auth.jwt() ->> 'is_anonymous')::boolean = true);
```

The anti-pattern is calling `deleteBucket` immediately after a single `emptyBucket` call without a retry loop.

### Why it's an anti-pattern
`emptyBucket` is **not synchronous**. Even when it returns `error: null`, the bucket may still contain objects for a short period. If you call `deleteBucket` immediately after, it will fail with a `409` error: `"The bucket you tried to delete is not empty"`.

### What you should do instead
You must implement a retry loop that calls `emptyBucket` multiple times, checking the bucket's contents with `list('')` between attempts, and only calling `deleteBucket` once the bucket is confirmed empty.

**Recommended pattern:**
```typescript
async function emptyAndDeleteBucket(id: string): Promise<void> {
  try {
    // Attempt to empty the bucket up to 5 times
    for (let i = 0; i < 5; i++) {
      await admin.storage.emptyBucket(id);

      // Check if the bucket is actually empty
      const { data } = await admin.storage.from(id).list('');
      if (!data || data.length === 0) break;

      // Wait briefly before retrying
      await new Promise((r) => setTimeout(r, 250));
    }

    // Now it is safe to delete
    await admin.storage.deleteBucket(id);
  } catch (err) {
    // Handle or audit error
  }
}

// Usage in tests
afterAll(async () => {
  await emptyAndDeleteBucket(BUCKET);
});
```

**Key takeaways:**
- `emptyBucket` should be treated as a "schedule delete" rather than an immediate wipe.
- Always verify the bucket is empty using `list('')` before calling `deleteBucket`.
- A small delay (e.g., 250ms) between retries is necessary to allow the storage backend to catch up.

The canonical BFF (Backend-for-Frontend) pattern in Supabase uses an Edge Function to act as a proxy that forwards the caller's JWT to the database. This allows the function to perform server-side aggregation (e.g., calculating a summary) while still respecting Row Level Security (RLS) because the database sees the caller's identity, not a service-role bypass.

### The Pattern
1.  **Extract** the `Authorization` header from the incoming request.
2.  **Initialize** a `supabase-js` client inside the function using the caller's JWT.
3.  **Query** the database; PostgREST receives the JWT and applies RLS.
4.  **Aggregate** the results on the server (e.g., count, sum, percent).
5.  **Return** the computed shape to the client.

### Implementation

```ts
// supabase/functions/au-bff-todos-summary/index.ts
import "jsr:@supabase/functions-js/edge-runtime.d.ts";
import { createClient } from "npm:@supabase/supabase-js@2.105.4";

// CORS headers are required for browser-based calls
const CORS = {
  "access-control-allow-origin": "*",
  "access-control-allow-methods": "GET, POST, OPTIONS",
  "access-control-allow-headers": "authorization, x-client-info, apikey, content-type",
};

Deno.serve(async (req: Request) => {
  // 0) Handle CORS preflight
  if (req.method === "OPTIONS") {
    return new Response(null, { status: 204, headers: CORS });
  }

  const requestId = req.headers.get("sb-execution-id") ?? "none";

  // 1) Require Authorization header
  const authHeader = req.headers.get("Authorization");
  if (!authHeader) {
    console.log(JSON.stringify({ event: "bff_no_auth", request_id: requestId }));
    return new Response(
      JSON.stringify({ code: "BFF_NO_AUTH" }),
      { status: 401, headers: { ...CORS, "content-type": "application/json" } },
    );
  }

  // 2) Build a caller-context supabase-js client
  // We use the ANON key + the caller's Bearer JWT to ensure RLS is applied
  const url = Deno.env.get("SUPABASE_URL")!;
  const anon = Deno.env.get("SUPABASE_ANON_KEY")!;
  const supa = createClient(url, anon, {
    global: { headers: { Authorization: authHeader } },
    auth: { persistSession: false, autoRefreshToken: false },
  });

  // 3) Query — RLS filters rows to the caller automatically
  const t0 = Date.now();
  const { data: todos, error } = await supa
    .from("todos")
    .select("id, user_id, title, completed");
  const queryMs = Date.now() - t0;

  if (error) {
    console.log(JSON.stringify({
      event: "bff_query_error",
      code: error.code,
      msg: error.message,
      queryMs,
      request_id: requestId,
    }));
    return new Response(
      JSON.stringify({ code: "APP_QUERY_FAILED", detail: error.code }),
      { status: 500, headers: { ...CORS, "content-type": "application/json" } },
    );
  }

  // 4) Server-side aggregation (the "BFF" value-add)
  const list = (todos ?? []) as any[];
  const total = list.length;
  const completed = list.filter((t) => t.completed).length;
  const percent_done = total === 0 ? 0 : Math.round((completed / total) * 100);

  // 5) Structured log event for observability
  console.log(JSON.stringify({
    event: "bff_summary",
    total,
    completed,
    percent_done,
    queryMs,
    request_id: requestId,
  }));

  // 6) Return the computed shape
  return new Response(
    JSON.stringify({ total, completed, percent_done, queryMs }),
    { status: 200, headers: { ...CORS, "content-type": "application/json" } },
  );
});
```

### Why this is the canonical pattern
*   **Security:** By using the caller's JWT instead of the `SERVICE_ROLE_KEY`, you never bypass RLS. If a user tries to call the BFF, they only see the data they are authorized to see.
*   **Efficiency:** The client receives a small, computed summary (e.g., `percent_done`) rather than downloading the entire list of todos and calculating it in the browser.
*   **Observability:** The function logs structured JSON events (including `queryMs` and `request_id`), allowing you to monitor BFF performance and error rates in your logs.
*   **Observability (Client-side):** Returning `queryMs` in the response allows the client to track how much of the total request latency was database-bound vs. network-bound.

The proven pattern for redacting `execSync` errors when working with Supabase involves two distinct steps: **preventing the token from appearing in the command string** and **sanitizing the error message** if a failure occurs.

### 1. Pass PAT via `env:`, NEVER inline in the command string
When you inline a token in a command string (e.g., `SUPABASE_ACCESS_TOKEN=sbp_xxx supabase ...`), the token is visible in the OS process list and, crucially, Node.js embeds the entire command string into the `Error.message` if the process fails.

**Correct approach:**
```ts
import { execSync } from "node:child_process";

const REF = process.env.SUPABASE_PROJECT_REF!;
const PAT = process.env.SUPABASE_ACCESS_TOKEN!;

// RIGHT — PAT is in env, command is clean
execSync(`supabase functions list --project-ref ${REF}`, {
  encoding: "utf8",
  env: { ...process.env, SUPABASE_ACCESS_TOKEN: PAT },
});
```

### 2. Regex-replace in `catch`
Even with the token in `env:`, the Supabase CLI might output sensitive information in its error messages (like JWTs or other keys). You should wrap the call in a `try/catch` and apply regex redaction to the error message before logging or re-throwing.

**Redaction implementation:**
```ts
try {
  execSync(`supabase functions delete ${SLUG} --project-ref ${REF}`, {
    encoding: "utf8",
    timeout: 60_000,
    input: "y\n",
    env: { ...process.env, SUPABASE_ACCESS_TOKEN: PAT },
  });
} catch (e) {
  const msg = (e as Error)?.message ?? String(e);
  const sanitized = msg
    .replace(/sbp_[A-Za-z0-9]+/g, "sbp_REDACTED") // PAT format
    .replace(/sb_secret_[A-Za-z0-9]+/g, "sb_secret_REDACTED") // short-key service-role
    .replace(/eyJ[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+/g, "JWT_REDACTED") // legacy JWTs
    .slice(0, 500); // Truncate to prevent log bloat

  console.error(`[cleanup] err preview=${sanitized}`);
}
```

### Summary of Redaction Patterns
| Pattern | Target |
| :--- | :--- |
| `/sbp_[A-Za-z0-9]+/g` | Supabase Personal Access Token (PAT) |
| `/sb_secret_[A-Za-z0-9]+/g` | Short-key service-role |
| `/eyJ[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+/g` | Legacy JWT format |

**Note:** This pattern does *not* prevent leaks if you `console.log(PAT)` directly; it only protects against the CLI/Node.js leaking the token via error messages.

The anti-pattern **AP-001: Using boolean `false` (or any falsy value) as a `Command` resume value** occurs when you attempt to use a falsy value (like `false`, `0`, `null`, or `""`) as the `resume` payload in a LangGraph `Command` object.

### Why it fails
Internally, LangGraph's `mapCommand` function uses a falsy check (`if (cmd.resume)`) to determine if it should produce writes. When you pass a falsy value:
1. `mapCommand` yields **zero writes**.
2. The Pregel runner receives an empty input.
3. The runner throws an `EmptyInputError: Received empty Command input`.

This is particularly dangerous in human-in-the-loop flows where developers naturally want to model an "approved/rejected" decision using `true`/`false`. The "rejected" path (using `false`) will crash the graph.

### What not to do
Avoid using any falsy value as a resume payload:
```typescript
// ALL OF THESE WILL THROW EmptyInputError
new Command({ resume: false });
new Command({ resume: 0 });
new Command({ resume: null });
new Command({ resume: "" });
```

### Do instead: Use string sentinels
Always use non-empty string sentinels for approval/rejection-style flows. Convert the string to a boolean inside the node that receives the interrupt.

**Correct pattern:**
```typescript
// 1. Use string sentinels for the Command
new Command({ resume: "approved" }); // OK
new Command({ resume: "rejected" }); // OK

// 2. Inside the node, convert the string to your desired boolean
const decision = interrupt(...) as string;
return { 
  approved: decision === "approved" 
};
```

**Evidence:**
- `/Users/dennison/develop/agent-university/langgraph/03-pocs/L4-human-in-the-loop/surprises.md` lines 62-85
- `/Users/dennison/develop/agent-university/langgraph/03-pocs/L4-human-in-the-loop/evidence.md` lines 23-25

The anti-pattern **AP-001: Calling `process.exit(0)` without `await flush()`** occurs when a script or serverless function terminates the process immediately after a traced operation without ensuring the SDK's internal trace queue has been emptied.

### The Anti-Pattern
The SDK enqueues runs on an internal `p-queue` with a **250ms auto-batch timer**. When `process.exit(0)` is called, the Node.js event loop is terminated immediately, killing the timer before it can fire. This results in **100% data loss** for traces that haven't been sent yet.

**Example of the anti-pattern:**
```typescript
import { traceable } from "langsmith/traceable";

const wrapped = traceable(async () => {
  // ... your work
}, { name: "shortLivedScript" });

await wrapped();
process.exit(0);   // ← traces are silently dropped 100% of the time
```

### The Fix
You must use the canonical pattern **P-001**, which wraps the work in a `try...finally` block to ensure `flush()` is called even if the traced operation fails.

**Correct implementation:**
```typescript
import { RunTree } from "langsmith/run_trees";

try {
  await wrapped();
} finally {
  // Ensure the internal queue is flushed before exiting
  await RunTree.getSharedClient().flush();
}
process.exit(0);
```

### Key Takeaways
* **Severity**: Blocker (100% data loss reproducible).
* **Why it fails**: A typical `flush()` takes 200–542ms, which is longer than the 250ms auto-batch timer period. The auto-batch timer cannot reliably win the race against a process exit.
* **Implicit version**: The same issue occurs if the script simply finishes its top-level await without an explicit `process.exit()`; the Node.js event loop drains and the queue is abandoned.

To implement TUS resumable uploads with Supabase Storage, you use the `tus-js-client` library. Supabase provides a TUS-compliant endpoint at `/storage/v1/upload/resumable`.

### Key Requirements
1.  **Endpoint:** `${SUPABASE_URL}/storage/v1/upload/resumable`
2.  **Headers:**
    *   `Authorization: Bearer <JWT>` (User JWT for RLS-scoped uploads, or Service Role key for bypass).
    *   `x-upsert: true` (Allows overwriting existing objects).
3.  **Metadata:** You **must** include `bucketName`, `objectName`, and `contentType` in the TUS metadata.
4.  **Chunk Size:** Must be **≥ 6 MiB** (except for the final chunk).

### Implementation (TypeScript)

```typescript
import * as tus from 'tus-js-client';

/**
 * Uploads a file using TUS resumable protocol to Supabase Storage.
 * 
 * @param file - The Blob or File to upload
 * @param bucket - The target Supabase bucket name
 * @param path - The destination path within the bucket (e.g., 'folder/image.png')
 * @param userJwt - Optional user JWT for RLS-scoped uploads (omit for service-role)
 * @param onProgress - Optional progress callback (sentBytes, totalBytes)
 */
export async function uploadResumable(
  file: Blob | File,
  bucket: string,
  path: string,
  userJwt?: string,
  onProgress?: (sent: number, total: number) => void
): Promise<string> {
  const SUPABASE_URL = process.env.SUPABASE_URL!;
  const auth = userJwt ?? process.env.SUPABASE_SERVICE_ROLE_KEY!;

  return new Promise((resolve, reject) => {
    const upload = new tus.Upload(file, {
      endpoint: `${SUPABASE_URL}/storage/v1/upload/resumable`,
      retryDelays: [0, 1000, 3000, 5000],
      headers: {
        authorization: `Bearer ${auth}`,
        'x-upsert': 'true',
      },
      uploadDataDuringCreation: true,
      metadata: {
        bucketName: bucket,
        objectName: path,
        contentType: (file as any).type ?? 'application/octet-stream',
        cacheControl: '3600',
      },
      chunkSize: 6 * 1024 * 1024, // 6 MiB minimum
      onError: (err) => {
        console.error('TUS Upload Error:', err);
        reject(err);
      },
      onProgress: (sent, total) => {
        if (onProgress) onProgress(sent, total);
      },
      onSuccess: () => {
        console.log('Upload successful:', upload.url);
        resolve(upload.url!);
      },
    });

    upload.start();
  });
}
```

### How to Resume an Interrupted Upload
If an upload is interrupted, you can resume it by passing the `uploadUrl` (the TUS resource URL) back into the `tus.Upload` constructor.

```typescript
// To resume, use the same metadata and the uploadUrl from the previous session
const upload = new tus.Upload(file, {
  endpoint: `${SUPABASE_URL}/storage/v1/upload/resumable`,
  uploadUrl: previousUploadUrl, // The URL returned by upload.url after interruption
  headers: {
    authorization: `Bearer ${auth}`,
    'x-upsert': 'true',
  },
  metadata: {
    bucketName: bucket,
    objectName: path,
    contentType: 'image/png',
    cacheControl: '3600',
  },
  // ... rest of config
});
upload.start();
```

### Important Gotchas
*   **Oversize Rejection:** If the file exceeds the bucket's max file size, the TUS server will reject the **initial creation POST** with an HTTP 413. This happens before any chunks are sent.
*   **Error Handling:** When an error occurs, check `error.statusCode` (as a string) to distinguish between RLS denials (`"403"`), file too large (`"413"`), or bucket not found (`"404"`).
*   **Chunk Size:** While 6 MiB is the recommended minimum, you can increase it for better performance on stable connections. The last chunk may be smaller than the `chunkSize`.

The proven pattern for a **Stateful counter agent with `setState` + per-instance routing** on Cloudflare is implemented using the `agents` SDK with a Durable Object-backed class.

### 1. Implementation Pattern (`src/index.ts`)
The agent extends the `Agent` class, uses `this.state` for persistence, and `this.setState()` to update it. Routing is handled within `onRequest` by inspecting the URL pathname.

```typescript
import { Agent, routeAgentRequest, type AgentNamespace } from 'agents';

type State = { count: number };

export class CounterAgent extends Agent<Env, State> {
  initialState: State = { count: 0 };

  async onRequest(request: Request): Promise<Response> {
    const url = new URL(request.url);

    if (url.pathname.endsWith('/increment')) {
      const current = this.state.count;
      this.setState({ count: current + 1 });
      return Response.json({ count: current + 1 });
    }

    if (url.pathname.endsWith('/state')) {
      return Response.json(this.state);
    }

    return new Response(
      JSON.stringify({ error: 'Use /increment or /state', pathname: url.pathname }),
      { status: 400, headers: { 'Content-Type': 'application/json' } }
    );
  }
}

export interface Env {
  CounterAgent: AgentNamespace<CounterAgent>;
}

export default {
  async fetch(request: Request, env: Env, ctx: ExecutionContext): Promise<Response> {
    return (
      (await routeAgentRequest(request, env)) ??
      new Response('Not found', { status: 404 })
    );
  },
};
```

### 2. Configuration (`wrangler.toml`)
**Crucial:** You must include `nodejs_compat` and a `new_sqlite_classes` migration for state to persist.

```toml
name = "agent-univ-test-counter-agent"
main = "src/index.ts"
compatibility_date = "2025-09-23"
compatibility_flags = ["nodejs_compat"]
workers_dev = true

[[durable_objects.bindings]]
name = "CounterAgent"          # Must match class name exactly
class_name = "CounterAgent"

[[migrations]]
tag = "v1"
new_sqlite_classes = ["CounterAgent"]   # REQUIRED for state persistence
```

### 3. Per-Instance Routing Contract
The SDK automatically converts the class name to kebab-case and routes requests based on the URL structure:
`/agents/<class-kebab>/<instance-name>/<path>`

**Example routing for `CounterAgent`:**
- `/agents/counter-agent/alice/increment` → Increments instance "alice"
- `/agents/counter-agent/alice/state` → Returns state for instance "alice"
- `/agents/counter-agent/bob/state` → Returns state for instance "bob" (independent of "alice")

### 4. Verified Behavior
Live testing confirms per-instance isolation:
1. `GET /agents/counter-agent/instance-A/increment` → `{"count": 1}`
2. `GET /agents/counter-agent/instance-A/increment` → `{"count": 2}`
3. `GET /agents/counter-agent/instance-B/state` → `{"count": 0}` (independent)
4. `GET /agents/counter-agent/instance-A/state` → `{"count": 2}`

The **P-01: The default-export-factory extension pattern** is the fundamental
contract for all pi extensions. It allows pi to dynamically load behavior
without a compile step, manifest, or `package.json`.

### The Pattern
Every pi extension must be a TypeScript file that **default-exports a single
function** taking the `ExtensionAPI` as its argument. Pi loads the file via
`jiti` at runtime and calls this function to register tools, commands, and
event listeners.

### Implementation Template
```ts
import { Type } from "@earendil-works/pi-ai";
import {
  defineTool,
  type ExtensionAPI,
  type ExtensionCommandContext,
} from "@earendil-works/pi-coding-agent";

// Module-scope state is fine; the extension is loaded once per pi start.
let counter = 0;

const myTool = defineTool({
  name: "my_tool",
  label: "My Tool",
  description: "What it does",
  parameters: Type.Object({ /* TypeBox schema */ }),
  async execute(_toolCallId, params, _signal, _onUpdate, _ctx) {
    counter += 1;
    return { content: [{ type: "text", text: "result text" }] };
  },
});

export default function (pi: ExtensionAPI) {
  // Register the tool
  pi.registerTool(myTool);

  // Register event listeners
  pi.on("tool_call", (event, _ctx) => {
    process.stderr.write(`[HOOK] ${(event as { toolName: string }).toolName}\n`);
  });

  // Optional: pi.registerCommand, pi.on(other events), etc.
}
```

### Key Rules
1.  **No Manifest Required**: You do not need a `package.json` or any
    metadata file. The file itself is the extension.
2.  **Discovery**: Pi auto-loads all `.ts` or `.js` files in these directories:
    - `<cwd>/.pi/extensions/*.ts` (Project-local, highest priority)
    - `~/.pi/agent/extensions/*.ts` (User-global)
3.  **Silent Failure**: If you do not default-export a function, pi will
    silently skip the file without an error message in print mode.
4.  **Module-Scope State**: Since the extension is loaded once per pi
    process, you can use module-level variables (like `counter` above) to
    maintain state across multiple tool calls or events.

### Evidence
This pattern is live-verified across multiple levels of the Agent University
curriculum:
- **L3**: `dice_roll` extension (verified via `[L3-HOOK]` stderr output).
- **L5**: `bash-guard` extension.
- **L-Capstone**: `audit-log` extension (verified via `pi --mode rpc` driven
  from Python).

To run the Claude Code harness headless inside a Vercel Sandbox microVM, you need two files: the orchestrator (`run-poc.mjs`) and the agent entrypoint (`agent-entrypoint.mjs`).

### 1. The Orchestrator (`run-poc.mjs`)
This script creates the sandbox, writes the entrypoint, installs the SDK inside the microVM, and runs the harness.

```javascript
import { Sandbox } from "@vercel/sandbox";
import { readFileSync } from "node:fs";

const sandbox = await Sandbox.create({
  runtime: "node22",
  timeout: 10 * 60 * 1000,
  resources: { vcpus: 2 },
  persistent: false,
  env: { ANTHROPIC_API_KEY: process.env.ANTHROPIC_API_KEY }, // model auth INSIDE the VM
});

await sandbox.writeFiles([
  { path: "agent-entrypoint.mjs", content: readFileSync("agent-entrypoint.mjs") },
  { path: "package.json", content: Buffer.from(JSON.stringify({ type: "module" })) },
]);

// Install the harness inside the microVM — pulls the linux-x64 bundled `claude` binary.
const install = await sandbox.runCommand({ 
  cmd: "npm", 
  args: ["install", "@anthropic-ai/claude-agent-sdk@latest"], 
  cwd: "/vercel/sandbox" 
});
if (install.exitCode !== 0) throw new Error("install failed");

// Run the harness headless.
const run = await sandbox.runCommand({
  cmd: "node", 
  args: ["agent-entrypoint.mjs"], 
  cwd: "/vercel/sandbox",
  env: { ANTHROPIC_API_KEY: process.env.ANTHROPIC_API_KEY },
});

console.log(await run.stdout());

// INDEPENDENT verification — trust the filesystem, not the model's reply.
const proof = (await sandbox.fs.readFile("/vercel/sandbox/proof.txt", "utf8")).trim();
console.log("verified:", proof === String(6857 * 7919));

await sandbox.stop();
```

### 2. The Agent Entrypoint (`agent-entrypoint.mjs`)
This is the code that actually runs *inside* the sandbox.

```javascript
import { query } from "@anthropic-ai/claude-agent-sdk";

for await (const m of query({
  prompt: "Use Bash to compute 6857*7919, Write only the number to /vercel/sandbox/proof.txt, Read it back, stop.",
  options: { 
    maxTurns: 12, 
    permissionMode: "bypassPermissions", 
    allowedTools: ["Bash","Read","Write"], 
    cwd: "/vercel/sandbox" 
  },
})) { 
  if (m.type === "result") console.log(m.result); 
}
```

### 3. Run it
Ensure you have your `ANTHROPIC_API_KEY` set in your environment.

```bash
# Using --env-file for Node.js 20.6+
ANTHROPIC_API_KEY='sk-ant-...' node --env-file=.env.local run-poc.mjs
```

### Key Details
- **Sandbox Isolation**: The `claude` binary and all tool executions (Bash, Read, Write) happen entirely within the Vercel Sandbox microVM.
- **Permission Mode**: `permissionMode: "bypassPermissions"` is used to allow the harness to run tools without interactive user approval, which is required for headless execution.
- **Verification**: The orchestrator verifies the result by reading `/vercel/sandbox/proof.txt` directly from the sandbox filesystem rather than trusting the model's text output.

To implement a `streamEvents` v3 consumer in LangGraph, you must follow a two-step pattern: first `await` the call to get the `GraphRunStream`, then use `for await` to iterate over the events.

### Implementation

```typescript
type V3Event = {
  type: "event";
  seq: number;
  method: "lifecycle" | "checkpoints" | "values" | "tasks" | "messages" | "updates";
  params: { namespace: string[]; timestamp: number; data: any };
};

const cfg = { version: "v3" as const, configurable: { thread_id: "stream-1" } };

// 1. CRITICAL: await the call to get the GraphRunStream (G-012)
const run = await compiled.streamEvents(
  { question: "How does human-in-the-loop work in LangGraph?" },
  cfg,
);

const events: V3Event[] = [];

// 2. Iterate using for-await
for await (const e of run as AsyncIterable<V3Event>) {
  events.push(e);
}

// 3. Access the final state via the .output Promise
const finalState = await run.output;
// e.g., finalState.finalAnswer === "Human-in-the-loop pauses graph execution using `interrupt()`..."
```

### Routing by `method`

Once collected, you can route events by their `method` property:

```typescript
const lifecycle = events.filter(e => e.method === "lifecycle");
const checkpoints = events.filter(e => e.method === "checkpoints");
const updates = events.filter(e => e.method === "updates");
const messages = events.filter(e => e.method === "messages");
const tasks = events.filter(e => e.method === "tasks");

// Pair node start/finish by data.id
const nodeStarts = tasks.filter(e => e.params.data.input);
const nodeEnds   = tasks.filter(e => e.params.data.result);
```

### Key Reminders

*   **G-012**: You **must** `await` the `streamEvents(...)` call before iterating. It returns a `Promise<GraphRunStream>`, not an `AsyncIterable` directly.
*   **Tool Calls**: `GraphRunStream` does **not** have a `.toolCalls` property (that was `AgentRunStream` in LangChain). To observe tool calls in v3, watch `messages` events where `data.content.type` is `"tool_call_chunk"` (start) or `"tool_call"` (finish).

Based on the live-verified corpus, the key takeaway from **Lesson L2: Configuration and State** regarding Composio is the concept of the **`auth_config` (`ac_*`)**.

### 1. The `auth_config` is Project-Scoped
An `auth_config` is not a per-user or per-test-run object; it is scoped to a **project**. You should create it once per (project, toolkit, managed-or-custom) and reuse it across all subsequent lessons (L2 through L5) and the Capstone.

### 2. Reuse, Don't Recreate
The pattern for L2 is to **resolve or create** the `auth_config` rather than blindly creating a new one. This ensures that your tests and subsequent lessons use the same credentials and state.

**Implementation Pattern:**
```ts
const composio = createComposioClient();

// 1. List existing auth_configs for the toolkit
const list = await composio.authConfigs.list({
  toolkit: 'github',
  isComposioManaged: true,
});
const items = Array.isArray(list) ? list : ((list as any).items ?? []);

// 2. Check if a managed auth_config already exists
const existing = items.find((c: any) => c.isComposioManaged !== false);

let authConfigId: string;
if (existing) {
  // Reuse the existing one
  authConfigId = existing.id;
} else {
  // Create a new one only if it doesn't exist
  const created = await composio.authConfigs.create('github', {
    type: 'use_composio_managed_auth',
    name: `myapp github managed (${new Date().toISOString()})`,
  });
  authConfigId = created.id;   // e.g., 'ac_a7Yhi0BJznwJ'
}
```

### Summary Table
| Concept | Scope | Lifecycle |
| :--- | :--- | :--- |
| **`auth_config` (`ac_*`)** | Project-scoped | Created once per toolkit; reused across L2–L5 and Capstone. |
| **Managed Auth** | Managed by Composio | Use `type: 'use_composio_managed_auth'` for easier setup. |

The recommended approach is to multiplex all three surfaces—**broadcast**, **presence**, and **postgres_changes**—over a single **private Supabase Realtime channel** scoped to a specific team ID.

### 1. Implementation Approach

#### Data Model & Security
*   **Durable Messages Table:** Create a `public.messages` table with a `team_id` column.
*   **Table-Layer RLS:** Enable RLS on the table. Only allow `SELECT` and `INSERT` for users who belong to that team (e.g., via a JWT claim or a membership table).
*   **Realtime Publication:** Add the table to the `supabase_realtime` publication and set `REPLICA IDENTITY FULL` to ensure `UPDATE` events include the old values.
*   **Channel-Layer RLS:** Create policies on `realtime.messages` that allow `SELECT` and `INSERT` only if the `realtime.topic()` matches the team's channel name (e.g., `au-team-123`) and the user is authenticated.

#### Client-Side Subscription
```ts
const topic = `au-team-${teamId}`;
const channel = supabase
  .channel(topic, {
    config: {
      private: true,
      broadcast: { self: true, ack: true }, // self: true lets the sender see their own broadcast
      presence: { key: userId },           // stable key across reconnects
    },
  })
  .on('broadcast', { event: 'chat' }, (msg) => onChat(msg.payload))
  .on('presence', { event: 'sync' }, () => onPresenceSync(channel.presenceState()))
  .on('postgres_changes', { 
    event: 'INSERT', 
    schema: 'public', 
    table: 'messages', 
    filter: `team_id=eq.${teamId}` 
  }, (payload) => onMessagePersisted(payload.new))
  .subscribe((status) => {
    if (status === 'SUBSCRIBED') {
      // CRITICAL: Wait ~1.5s for private channel postgres_changes to settle (Gap #59)
      setTimeout(() => channel.track({ user_id: userId, status: 'online' }), 1500);
    }
  });
```

### 2. Why This Works

| Feature | Mechanism | Benefit |
| :--- | :--- | :--- |
| **Single Connection** | Multiplexing | All three surfaces share one WebSocket; minimal overhead and easier state management. |
| **Two-Layer Auth** | `realtime.messages` RLS + Table RLS | **Channel-layer RLS** prevents non-members from even subscribing to the topic. **Table-layer RLS** prevents non-members from inserting messages or seeing the persisted history. |
| **Ephemeral + Durable** | Broadcast + Postgres | **Broadcast** provides low-latency "typing" indicators and chat fan-out. **Postgres_changes** provides the durable, queryable message log. |
| **`broadcast.self: true`** | Self-acknowledgment | The sender's chat handler renders their own message using the same logic as peers, simplifying UI code. |
| **`presence.key`** | Stable Identity | Using a `userId` as the presence key ensures a user's presence state is stable across session reconnects. |
| **Server-Side Filtering** | `filter: team_id=eq...` | The Postgres event is filtered at the server level; users only receive changes for their specific team. |

### 3. Critical Gotchas
*   **The 1.5s Settle:** On private channels, the first `postgres_changes` event can be dropped if it arrives immediately after subscription. Always wait ~1.5s before tracking presence or expecting the first DB event.
*   **Cleanup:** Always call `channel.unsubscribe()` and `supabase.realtime.disconnect()` in your test `afterAll` or component unmount to prevent residual connections.

The mistake is **using model IDs that were valid at the time of LLM training but are now deprecated or removed from the Cloudflare Workers AI catalog.**

### The Mistake
Developers often copy-paste model IDs from LLM-generated code or older tutorials (e.g., `@cf/meta/llama-2-7b-chat-int8`, `@cf/microsoft/phi-2`, or `@cf/mistral/mistral-7b-instruct-v0.1`). Because LLM training data has a knowledge cutoff, these IDs may have been valid 6–18 months ago but are now flagged as "Planned deprecation" or have been removed entirely. This leads to runtime "model not found" errors and silent production failures when the model eventually vanishes.

### The Right Way
1.  **Verify against the live catalog:** Always check the current [Cloudflare Workers AI models page](https://developers.cloudflare.com/workers-ai/models/) before deploying.
2.  **Prefer GA models without "Planned deprecation":** As of May 2026, safer choices include:
    *   `@cf/meta/llama-3.3-70b-instruct-fp8-fast` (text gen, function calling, batch)
    *   `@cf/meta/llama-3.2-3b-instruct` (small text gen)
    *   `@cf/qwen/qwen3-30b-a3b-fp8` (text gen)
    *   `@cf/mistralai/mistral-small-3.1-24b-instruct` (text gen, 128k context)
3.  **Use configuration variables:** Never hardcode model IDs. Set them in `wrangler.toml` under `[vars]` or pass them via environment variables.
4.  **Implement a fallback chain:** Wrap your AI calls in a try/catch block that retries with an alternate model if the primary fails.

**Correct Implementation Pattern:**
```typescript
// Config-driven with fallback
const PRIMARY = env.MODEL_PRIMARY ?? '@cf/meta/llama-3.3-70b-instruct-fp8-fast';
const FALLBACK = env.MODEL_FALLBACK ?? '@cf/meta/llama-3.2-3b-instruct';

try {
  return await env.AI.run(PRIMARY, { prompt, max_tokens: 100 });
} catch (err) {
  console.log(JSON.stringify({ event: 'model_fallback', primary: PRIMARY, fallback: FALLBACK }));
  return await env.AI.run(FALLBACK, { prompt, max_tokens: 100 });
}
```

To implement 'Claude Code' with agent-hooks, you must use the specific `.claude/settings.json` wrapper format required by the Claude Code CLI. A common pitfall is providing a flat array of hooks, which Claude Code silently ignores without error.

### 1. The Settings File (`.claude/settings.json`)
The hooks must be wrapped in a `{"hooks": { ... }}` object. Each event (e.g., `on_tool_call`, `on_file_change`) contains an array of hook objects with a `matcher` (glob pattern) and a `command`.

```json
{
  "hooks": {
    "on_tool_call": [
      {
        "matcher": "src/**/*.ts",
        "hooks": [
          {
            "name": "log-tool-usage",
            "command": "node .claude/hooks/log-tool.mjs",
            "args": ["--project", "my-app"]
          }
        ]
      }
    ],
    "on_file_change": [
      {
        "matcher": "src/api/**/*",
        "hooks": [
          {
            "name": "trigger-test",
            "command": "npm",
            "args": ["test", "--", "src/api/"]
          }
        ]
      }
    ]
  }
}
```

### 2. Implementation Details

#### A. The Hook Script (`.claude/hooks/log-tool.mjs`)
Claude Code passes hook context via `stdin` as a JSON object. Your script must read this stream to access the tool name, arguments, and file context.

```javascript
// .claude/hooks/log-tool.mjs
import { readFileSync } from 'fs';

async function main() {
  // Claude Code sends hook context via stdin
  const stdin = process.stdin;
  let input = '';

  for await (const chunk of stdin) {
    input += chunk;
  }

  if (!input) return;

  try {
    const context = JSON.parse(input);
    const { event, tool_name, tool_args, file_path } = context;

    // Log to a dedicated trace file for observability
    const logEntry = `[${new Date().toISOString()}] Event: ${event} | Tool: ${tool_name} | File: ${file_path}\n`;

    // Append to a local log file
    // Note: Ensure the script has write permissions in the project root
    process.stdout.write(logEntry); 
  } catch (err) {
    console.error('Failed to parse hook context:', err.message);
    process.exit(1);
  }
}

main();
```

#### B. Running in Headless Mode
When running Claude Code in a CI/CD pipeline or automated environment, use the `--headless` flag. This ensures hooks are executed without requiring interactive user confirmation for every tool call.

```bash
claude --headless --project-root . --debug-file ./claude-debug.log
```

### 3. Key Gotchas & Best Practices

*   **Wrapper Requirement**: Never use a flat array `[{event: '...', command: '...'}]`. It must be `{"hooks": { "EventName": [...] }}`.
*   **Matcher Scoping**: Use specific glob patterns (e.g., `src/**/*.ts`) to prevent hooks from firing on every single file change, which can significantly slow down the agent.
*   **Error Handling**: If a hook script exits with a non-zero code, Claude Code may halt the current turn. Always wrap your hook logic in `try/catch` and log errors to a file rather than just `stderr`.
*   **Observability**: Since hooks run as sub-processes, their `stdout` is often swallowed by the Claude Code process. Always redirect hook output to a file (e.g., `command: "node script.mjs >> ./hooks.log 2>&1"`) if you need to debug them.
*   **Model Compatibility**: When using the Claude Code proxy, ensure you are targeting Claude 4.5+ models (e.g., `anthropic/claude-sonnet-4-5`) for optimal tool-calling reliability.

To implement a two-client broadcast where Client A sends and Client B receives using Supabase Realtime, you must follow a specific sequence: **Client B (the receiver) must subscribe and register its listener before Client A (the sender) sends the message.**

### Implementation Pattern

```typescript
import { createClient, type RealtimeChannel } from '@supabase/supabase-js';

const URL = process.env.SUPABASE_URL!;
const ANON = process.env.SUPABASE_ANON_KEY!;

/**
 * Helper to wait for a channel to reach 'SUBSCRIBED' status.
 * Essential to avoid sending messages before the receiver is ready.
 */
async function subscribed(ch: RealtimeChannel, timeoutMs = 5000): Promise<void> {
  return new Promise((resolve, reject) => {
    const t = setTimeout(() => reject(new Error('subscribe timeout')), timeoutMs);
    ch.subscribe((status, err) => {
      if (status === 'SUBSCRIBED') {
        clearTimeout(t);
        resolve();
      } else if (status === 'CHANNEL_ERROR' || status === 'TIMED_OUT') {
        clearTimeout(t);
        reject(err ?? new Error(status));
      }
    });
  });
}

async function main() {
  const a = createClient(URL, ANON);
  const b = createClient(URL, ANON);

  // Use a unique topic for this session
  const topic = `au-broadcast-${Date.now()}`;

  // 1. CLIENT B (RECEIVER)
  // Must subscribe FIRST and register the listener before A sends.
  let receivedPayload: { text: string } | null = null;
  const chB = b.channel(topic).on('broadcast', { event: 'msg' }, (msg) => {
    receivedPayload = msg.payload as { text: string };
    console.log('B received:', receivedPayload);
  });
  await subscribed(chB);

  // 2. CLIENT A (SENDER)
  // Subscribe to the same topic.
  const chA = a.channel(topic, { config: { broadcast: { ack: true } } });
  await subscribed(chA);

  // 3. SEND MESSAGE
  // With ack: true, the result will be the string 'ok' upon successful delivery.
  const result = await chA.send({
    type: 'broadcast',
    event: 'msg',
    payload: { text: 'hello from A' },
  });
  console.log('A send result:', result); // 'ok'

  // 4. WAIT FOR DELIVERY
  // Give the network a moment to deliver the broadcast to B.
  await new Promise((r) => setTimeout(r, 2000));

  // 5. CLEANUP
  await a.removeAllChannels();
  await b.removeAllChannels();
  a.realtime.disconnect();
  b.realtime.disconnect();
}

main().catch(console.error);
```

### Key Implementation Details

1.  **Subscribe Order:** Always subscribe the receiver (B) before the sender (A). If A sends before B's subscription is fully established, B will miss the message.
2.  **The `subscribed` Helper:** Never call `.send()` immediately after `.channel().subscribe()`. You must wait for the `SUBSCRIBED` status callback to ensure the channel is active.
3.  **`ack: true`:** Enabling acknowledgments on the sender's channel configuration (`{ config: { broadcast: { ack: true } } }`) allows you to `await` the `.send()` call. It resolves to the string `'ok'` when the server acknowledges receipt.
4.  **Topic Uniqueness:** Use a unique topic (e.g., appending a timestamp) to prevent cross-talk between different test runs or users.
5.  **Cleanup:** Always call `removeAllChannels()` and `realtime.disconnect()` to prevent memory leaks and hanging connections in your application or test suite.

To implement **Recipe 02 — Streaming SSE Endpoint Over Hono on Vercel Fluid Compute**, you need to handle three critical "gotchas" identified in the live-verified evidence:
1.  **The Deadlock Gotcha:** You must iterate the `textStream` *before* awaiting `result.usage`. Awaiting usage first will deadlock the stream.
2.  **The Vercel Entry Gotcha:** Use `export default { fetch: app.fetch.bind(app) }` instead of `@hono/node-server/vercel` to prevent POST bodies from hanging on Fluid Compute.
3.  **The 404 Gotcha:** Explicitly set `app.notFound` to return JSON, as Hono's default text/plain response crashes clients expecting JSON.

### Implementation

#### 1. `src/server.ts` (The Streaming Factory)
This file contains the core logic for the SSE stream.

```ts
import { Hono } from 'hono';
import { streamText } from 'ai';
import { createGateway } from '@ai-sdk/gateway';
import { loadConfig } from './config.js';

const DEFAULT_MODEL = 'openai/gpt-5.4-nano';

export function createApp() {
  const app = new Hono();

  // [Live verified — L3 Surprise 3]
  // Hono's default 404 is text/plain — clients expecting JSON crash on res.json()
  app.notFound((c) => c.json({ error: 'Not found' }, 404));

  app.get('/health', (c) => {
    const cfg = loadConfig();
    return c.json({ status: 'ok', apiKeyMasked: cfg.apiKeyMasked, defaultModel: DEFAULT_MODEL });
  });

  app.post('/stream', async (c) => {
    const body = await c.req.json().catch(() => null);
    if (!body?.prompt || typeof body.prompt !== 'string') {
      return c.json({ error: 'Missing required field: prompt (must be a non-empty string)' }, 400);
    }

    const cfg = loadConfig();
    const gateway = createGateway({ apiKey: cfg.apiKey });
    const requestId = `caps-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`;
    const t0 = Date.now();

    console.log(JSON.stringify({ op: 'stream-request', requestId, promptLength: body.prompt.length }));

    const result = await streamText({
      model: gateway(DEFAULT_MODEL),
      prompt: body.prompt,
      maxOutputTokens: body.maxTokens ?? 200,
      providerOptions: {
        gateway: {
          zeroDataRetention: true,   // per-request ZDR — free at API-key level
          tags: ['streaming-recipe'],
        },
      },
    });

    const stream = new ReadableStream({
      async start(controller) {
        const encoder = new TextEncoder();
        let chunkCount = 0;
        let totalTextLength = 0;
        try {
          // [Live verified — Capstone Surprise 3]
          // CRITICAL: iterate the stream FIRST, then await result.usage
          // Awaiting result.usage before draining textStream deadlocks
          for await (const chunk of result.textStream) {
            chunkCount++;
            totalTextLength += chunk.length;
            controller.enqueue(encoder.encode(`data: ${JSON.stringify({ chunk })}\n\n`));
          }

          const usage = await result.usage;
          const latency_ms = Date.now() - t0;

          controller.enqueue(encoder.encode(`data: ${JSON.stringify({ 
            done: true, 
            usage, 
            latency_ms, 
            requestId 
          })}\n\n`));

          console.log(JSON.stringify({ 
            op: 'stream-complete', 
            requestId, 
            chunkCount, 
            totalTextLength, 
            latency_ms, 
            usage 
          }));
        } catch (err) {
          console.error(JSON.stringify({ op: 'stream-error', requestId, error: err instanceof Error ? err.message : String(err) }));
          controller.error(err);
        } finally {
          controller.close();
        }
      },
    });

    return c.body(stream, {
      headers: {
        'Content-Type': 'text/event-stream',
        'Cache-Control': 'no-cache',
        'Connection': 'keep-alive',
      },
    });
  });

  return app;
}
```

